  // ─── Login / Logout ───────────────────────────────────────────────────────

  private showLoginModal(): void {
    this.el("#login-overlay").style.display = "flex";
    this.el("#app-content").style.display = "none";
  }

  private hideLoginModal(): void {
    this.el("#login-overlay").style.display = "none";
    this.el("#app-content").style.display = "flex";
  }

  private async handleLogin(): Promise<void> {
    const input = this.el<HTMLInputElement>('[data-cy="username-input"]');
    const username = input.value.trim();
    if (!username) return;

    try {
      const res = await api.login(username);
      this.token = res.token;
      this.username = username;
      this.el("#login-error").textContent = "";
      this.hideLoginModal();
      this.el("#user-display").textContent = username;
      this.loadWorkspaces();
    } catch (err) {
      this.el("#login-error").textContent =
        err instanceof Error ? err.message : "Login failed";
    }
  }

  private async handleLogout(): Promise<void> {
    try {
      await api.logout(this.token);
    } catch (err) {
      slog.warn("Logout error", ["error", String(err)]);
    }
    this.closeChannel();
    this.closeWorkspace();
    this.token = "";
    this.username = "";
    this.el("#user-display").textContent = "";
    this.el<HTMLInputElement>('[data-cy="username-input"]').value = "";
    this.hideError();
    this.showLoginModal();
  }

  // ─── Error Banner ─────────────────────────────────────────────────────────

  private showError(msg: string): void {
    if (this.errorTimeout) clearTimeout(this.errorTimeout);
    this.el("#error-text").textContent = msg;
    this.el("#error-banner").style.display = "flex";
  }

  private hideError(): void {
    if (this.errorTimeout) {
      clearTimeout(this.errorTimeout);
      this.errorTimeout = null;
    }
    this.el("#error-banner").style.display = "none";
    this.el("#error-text").textContent = "";
  }

