 */
Cypress.Commands.add("openChannel", (channel: string) => {
  cy.get('[data-cy="ch-name-input"]').clear().type(channel);
  cy.get('[data-cy="ch-open-btn"]').click();
});

/**
 * Create a channel.
 * Assumes that someone is logged in, a workspace is open, and that the channel
 * does not exist in that workspace.
 */
Cypress.Commands.add("createChannel", (channel: string) => {
  cy.get('[data-cy="ch-name-input"]').clear().type(channel);
  cy.get('[data-cy="ch-create-btn"]').click();
});

/**
 * Delete a channel.
 * Assumes that someone is logged in, a workspace is open, and that the channel
 * exists in that workspace.
 */
Cypress.Commands.add("deleteChannel", (channel: string) => {
  cy.get('[data-cy="ch-name-input"]').clear().type(channel);
  cy.get('[data-cy="ch-delete-btn"]').click();
});

/**
 * Create a post.
 * Assumes that someone is logged in, a workspace is open, and a channel is open.
 */
Cypress.Commands.add("createPost", (post: string) => {
  cy.get('[data-cy="post-input"]').clear().type(post, { parseSpecialCharSequences: false });
  cy.get('[data-cy="post-submit-btn"]').click();
});

/**
 * Get a post.
 * Returns the post element that contains the searchText.
 */
Cypress.Commands.add(
  "getPost",
  (searchText: string): Cypress.Chainable<JQuery<Element>> => {
    return cy.contains('[data-cy="post-item"]', searchText);
  },
);

/**
 * Reply to a post.
 * The subject is the post element from getPost.
 */
Cypress.Commands.add(
  "replyToPost",
  { prevSubject: true },
  (subject, reply: string) => {
    cy.wrap(subject).find('[data-cy="reply-btn"]').click();
    cy.get('[data-cy="post-input"]').clear().type(reply, { parseSpecialCharSequences: false });
    cy.get('[data-cy="post-submit-btn"]').click();
  },
);

/**
 * React to a post.
 * The subject is the post element from getPost.
 */
Cypress.Commands.add(
  "reactToPost",
  { prevSubject: true },
  (subject, reaction: string) => {
    cy.wrap(subject).find(`[data-reaction="${reaction}"]`).click();
  },
);

