private async handleSubmitPost(): Promise<void> {
  const textarea = this.el<HTMLTextAreaElement>('[data-cy="post-input"]');
  const msg = textarea.value;
  if (!msg.trim()) return;
  if (!this.currentWorkspace || !this.currentChannel) return;

  const parent = this.replyParentPath;

  try {
    const uriRes = await api.createPost(
      this.token,
      this.currentWorkspace,
      this.currentChannel,
      msg,
      parent,
    );
    textarea.value = "";

    // Optimistic local update: add post immediately without waiting for SSE
    const postData: PostData = {
      path: uriRes.uri,
      msg,
      parent: parent || "",
      author: this.username,
      createdAt: Date.now(),
      reactions: {},
    };
    this.posts.set(uriRes.uri, postData);
    this.renderPosts();

    // If was replying, cancel reply mode
    if (parent) {
      this.cancelReply();
    }
  } catch (err) {
    slog.warn("Failed to create post", ["error", String(err)]);
  }
}

